import { Workflow, INode } from 'n8n-workflow';

function scanRecursiveAuth(workflow: Workflow): string[] {
  const issues: string[] = [];

  workflow.nodes.forEach(node => {
    if (isAIAgentNode(node) && hasCredentialDownstream(node)) {
      const connections = workflow.connectionsByDestinationNode[node.id];
      connections?.forEach(conn => {
        const targetNode = workflow.nodes.find(n => n.id === conn.node);
        if (targetNode?.type.includes('HttpRequest') && isLoopConnection(node, targetNode)) {
          issues.push(`Recursive auth exposure: ${node.name} → ${targetNode.name}`);
        }
      });
    }
  });

  return issues;
}

function isAIAgentNode(node: INode): boolean {
  return node.type === 'n8n-nodes-langchain.agent' || node.type.includes('aiAgent');
}

function detectToolCredentialLeaks(node: INode): string[] {
  const leaks: string[] = [];

  if (node.type === 'n8n-nodes-langchain.tool') {
    const parameters = node.parameters as any;

    // Check function code for common credential patterns
    const funcCode = parameters.jsCode || parameters.functionCode;
    if (funcCode) {
      const credPatterns = [
        /apiKey['"]?\s*[:=]\s*['"][A-Za-z0-9]{32,}/,
        /bearer\s+['"][A-Za-z0-9_-]+['"]/,
        /Authorization\s*[:=]\s*['"]/
      ];

      credPatterns.forEach(pattern => {
        if (pattern.test(funcCode)) {
          leaks.push(`Credential pattern found in tool ${node.name}`);
        }
      });
    }
  }

  return leaks;
}

function validateMemoryAuthTokens(node: INode): string[] {
  const issues: string[] = [];

  if (node.type === 'n8n-nodes-base.windowBufferMemory') {
    const params = node.parameters as any;
    const memoryContent = params.sessionId || params.memoryKey;

    // Check for expired token patterns in memory context
    if (memoryContent && /expired|invalid|401|403/.test(memoryContent)) {
      issues.push(`Stale auth tokens detected in ${node.name}`);
    }
  }

  return issues;
}

