// Add as Code node between AI Agent and credential nodes
const items = $input.all();
const safeOutputs: any[] = [];

for (const item of items) {
  const aiOutput = item.json;

  // Strip credentials from AI-generated parameters
  const sanitized = sanitizeAIOutput(aiOutput);

  // Validate authorization scope
  if (await validateAuthScope(sanitized)) {
    safeOutputs.push({ json: sanitized });
  }
}

return safeOutputs;

function sanitizeAIOutput(output: any): any {
  const forbidden = ['apiKey', 'bearer', 'Authorization', 'password'];
  const sanitized = { ...output };

  Object.keys(sanitized).forEach(key => {
    if (forbidden.includes(key.toLowerCase())) {
      delete sanitized[key];
    }
  });

  return sanitized;
}

// Secure tool function for AI Agent nodes
export function secureApiCaller(input: any) {
  // Never accept credentials as parameters
  const { endpoint, method = 'GET', payload } = input;

  // Use n8n credentials system
  const credentials = $credentials.apiService;

  return $http.request({
    method,
    url: endpoint,
    headers: {
      Authorization: `Bearer ${credentials.apiKey}`,
    },
    body: payload,
    timeout: 5000
  }).catch(err => ({
    error: 'Auth failed',
    status: err.statusCode
  }));
}

// Code node for memory window preprocessing
const memoryItems = $input.all();
const cleanedMemory: any[] = [];

for (const item of memoryItems) {
  const context = item.json;

  // Rotate expired auth tokens
  if (context.auth && isTokenExpired(context.auth.expires_at)) {
    context.auth = await refreshAuthToken(context.auth.refresh_token);
  }

  // Remove sensitive data before AI processing
  delete context.auth?.token;
  cleanedMemory.push({ json: context });
}

return cleanedMemory;

async function refreshAuthToken(refreshToken: string) {
  return await $http.request({
    method: 'POST',
    url: 'https://auth.provider/token',
    body: { refresh_token: refreshToken }
  });
}

